138→      if (!token) throw new Error('Please log in to comment.');
139→      if (!body) throw new Error('Comment cannot be empty.');
140→      if (!receiverId) throw new Error('Missing journal owner.');
141→      return socialApi.addComment(token, {comments: body, postId: journalId, receiverId});
142→    },
143→    onSuccess: () => {
