 96→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 97→  });
 98→
 99→  const markReadMutation = useMutation({
100→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
101→      socialApi.markNotificationRead(token, args.notifId, args.source),
102→    onSuccess: () => {
103→      queryClient.invalidateQueries({queryKey: ['notifications', userId]});
104→      queryClient.invalidateQueries({queryKey: ['notification-count', userId]});
105→    },
106→  });
107→
108→  const deleteMutation = useMutation({
